    page.click('button#inexistente', timeout=2000)
except Exception as e:
    print(f'Elemento não encontrado: {e}')

# Timeout em wait_for_selector
try:
    page.wait_for_selector('.carregando', timeout=5000, state='hidden')
except Exception as e:
    print(f'Elemento não desapareceu: {e}')

# Configurar timeout global
page.set_default_timeout(10000)  # 10 segundos
page.goto('https://example.com')  # usa timeout global

# Tentativa de clicar em elemento inexistente
try:
    page.click('button#nao-existe')
except Exception as e:
    print(f'Erro: {e}')

# Verificar antes de interagir
if page.query_selector('button#existe'):
    page.click('button#existe')
else:
    print('Botão não encontrado')

# Tentativa com wait_for_selector
if page.wait_for_selector('button', timeout=1000):
    page.click('button')

# Usar locator com fallback
button = page.locator('button.submit')
if button.count() > 0:
    button.click()
else:
    print('Nenhum botão submit encontrado')

# Tentativa em frame
try:
    frame = page.frame('nao-existe')
    frame.click('button')
except Exception as e:
    print(f'Frame não encontrado: {e}')

