# Opção com is_eager (processamento antecipado)
@click.command()
@click.option('--debug', is_flag=True, is_eager=True)
@click.option('--host', default='localhost')
def app(debug, host):
    if debug:
        click.echo('Modo debug ativado')
    click.echo(f'Host: {host}')

# Opção com count
@click.command()
@click.option('-v', '--verbose', count=True)
def log(verbose):
    click.echo(f'Nível de verbosidade: {verbose}')

# Opção com flag false
@click.command()
@click.option('--/--no', 'flag', default=True)
def opcao(flag):
    click.echo(f'Flag: {flag}')

if __name__ == '__main__':
    saudar()
    processar()
    servidor()
    login()
    pintar()
    localizar()
    executar()
    configurar()
    cumprimentar()
    cadastrar()
    conectar()
    app()
    log()
    opcao()

import click

# Grupo básico
@click.group()
def cli():
    """Ferramenta de linha de comando"""
    pass

@cli.command()
def init():
    """Inicializa o projeto"""
    click.echo('Projeto inicializado')

@cli.command()
@click.argument('nome')
def criar(nome):
    """Cria um novo recurso"""
    click.echo(f'Recurso {nome} criado')

# Grupo com configurações
@click.group(context_settings=dict(help_option_names=['-h', '--help']))
def db():
    """Comandos de banco de dados"""
    pass

@db.command()
def migrate():
    """Executa migrações"""
    click.echo('Migrações executadas')

@db.command()
@click.option('--force', is_flag=True)
def drop(force):
    """Remove o banco de dados"""
    if force:
        click.echo('Banco removido')
    else:
        click.echo('Use --force para confirmar')

# Grupo aninhado
@click.group()
def git():
    """Comandos Git"""
    pass

@git.group()
def remote():
    """Gerencia repositórios remotos"""
    pass

@remote.command()
@click.argument('nome')
def add(nome):
    """Adiciona um remote"""
    click.echo(f'Remote {nome} adicionado')

@remote.command()
def list():
    """Lista remotes"""
    click.echo('origin\nupstream')

# Grupo com comando herdado
@click.group()
@click.option('--debug', is_flag=True)
@click.pass_context
def cli(ctx, debug):
    """CLI principal"""
    ctx.ensure_object(dict)
    ctx.obj['DEBUG'] = debug

@cli.command()
@click.pass_context
def status(ctx):
    """Mostra status"""
    debug = ctx.obj.get('DEBUG', False)
    if debug:
        click.echo('Modo debug ativado')
    click.echo('Status: OK')

# Grupo com chain (múltiplos comandos)
@click.group(chain=True)
def cli_chain():
    """Comandos encadeáveis"""
    pass

@cli_chain.command()
def build():
    click.echo('Building...')

@cli_chain.command()
def test():
    click.echo('Testing...')

@cli_chain.command()
def deploy():
    click.echo('Deploying...')

# Grupo com invoke_without_command
@click.group(invoke_without_command=True)
@click.pass_context
def cli_invoke(ctx):
    """CLI que mostra ajuda se nenhum comando for fornecido"""
    if ctx.invoked_subcommand is None:
        click.echo('Nenhum comando especificado. Use --help para ajuda.')

@cli_invoke.command()
def start():
    click.echo('Iniciando...')

if __name__ == '__main__':
    cli()
    db()
    git()
    cli()  # para o grupo com pass_context
    cli_chain()
    cli_invoke()

import click

# Confirmação básica
if click.confirm('Deseja continuar?'):
    click.echo('Continuando...')
else:
    click.echo('Cancelado')

# Confirmação com padrão
if click.confirm('Deseja salvar?', default=True):
    click.echo('Salvando...')

# Confirmação com abort
if click.confirm('Deseja deletar?', abort=True):
    click.echo('Deletando...')

# Confirmação com prompt personalizado
if click.confirm('Continuar?', prompt_suffix=' (y/n) '):
    click.echo('Prosseguindo')

# Confirmação com default e abort
if click.confirm('Excluir todos os dados?', default=False, abort=True):
    click.echo('Dados excluídos')

# Confirmação em cascata
if click.confirm('Deseja iniciar o processo?'):
    if click.confirm('Tem certeza?', default=False):
        click.echo('Processo iniciado')
    else:
        click.echo('Processo cancelado')
else:
    click.echo('Operação cancelada')

# Confirmação com validação
while True:
    resposta = click.confirm('Confirmar ação?', default=False)
    if resposta:
        click.echo('Ação confirmada')
        break
    else:
        click.echo('Por favor, confirme para prosseguir')

# Confirmação para operação destrutiva
if click.confirm('⚠️  Isso irá deletar todos os arquivos. Continuar?', default=False, abort=True):
    click.echo('Arquivos deletados')

