import click

# Abort básico
@click.command()
def erro():
    click.echo('Ocorreu um erro')
    click.abort()

# Abort com condição
@click.command()
@click.argument('arquivo')
def processar(arquivo):
    if not arquivo.endswith('.txt'):
        click.echo('Erro: Arquivo deve ser .txt', err=True)
        click.abort()
    click.echo(f'Processando {arquivo}')

# Abort com tratamento
@click.command()
def testar():
    try:
        click.echo('Iniciando...')
        click.abort()
    except click.exceptions.Abort:
        click.echo('Abort capturado')
        # cleanup

# Abort em função
def validar_dados(dados):
    if not dados:
        click.echo('Dados vazios', err=True)
        click.abort()

@click.command()
@click.argument('dados')
def validar(dados):
    validar_dados(dados)
    click.echo('Dados válidos')

# Abort com código de saída
@click.command()
def fail():
    click.echo('Falha crítica')
    click.abort()
    # ou
    # sys.exit(1)

# Abort com mensagem
@click.command()
def check():
    if not click.confirm('Continuar?'):
        click.abort()
    click.echo('Continuando...')

# Abort com cleanup
temp_files = []

@click.command()
def cleanup():
    try:
        # Simular criação de arquivos temporários
        temp_files.append('/tmp/file1')
        temp_files.append('/tmp/file2')

        if not click.confirm('Processar?'):
            click.abort()

        click.echo('Processando...')
    except click.Abort:
        click.echo('Limpeza...')
        # Limpar arquivos temporários
        temp_files.clear()
        click.echo('Limpeza concluída')
        raise

if __name__ == '__main__':
    erro()
    processar()
    testar()
    validar()
    fail()
    check()
    cleanup()

import click
import webbrowser

# Launch básico
@click.command()
@click.argument('url', default='https://google.com')
def abrir(url):
    """Abre URL no navegador"""
    click.launch(url)
    click.echo(f'Abrindo {url}...')

# Launch com wait
@click.command()
def docs():
    """Abre documentação"""
    click.launch('https://click.palletsprojects.com', wait=True)
    click.echo('Documentação aberta')

# Launch com localize
@click.command()
def help_local():
    """Abre ajuda local"""
    import os
    path = os.path.abspath('docs/index.html')
    click.launch(f'file://{path}', locate=True)

# Launch com múltiplas URLs
@click.command()
def abrir_multiplas():
    """Abre múltiplas URLs"""
    urls = [
        'https://google.com',
        'https://github.com',
        'https://stackoverflow.com'
    ]

    for url in urls:
        if click.confirm(f'Abrir {url}?'):
            click.launch(url)
            click.echo(f'Aberto: {url}')

# Launch com browser específico
@click.command()
@click.option('--browser', default='chrome')
def abrir_browser(url):
    """Abre com browser específico"""
    try:
        if browser == 'chrome':
            webbrowser.get('chrome').open(url)
        elif browser == 'firefox':
            webbrowser.get('firefox').open(url)
        else:
            click.launch(url)
    except webbrowser.Error:
        click.echo('Browser não encontrado, usando padrão')
        click.launch(url)

# Launch com validação
@click.command()
@click.argument('url')
def abrir_url(url):
    """Abre URL com validação"""
    if not url.startswith(('http://', 'https://')):
        url = 'https://' + url

    if click.confirm(f'Abrir {url}?'):
        click.launch(url)
    else:
        click.echo('Cancelado')

# Launch em modo debug
@click.command()
@click.option('--dry-run', is_flag=True)
def preview(dry_run):
    """Previsualiza URLs"""
    urls = ['https://site1.com', 'https://site2.com']

    for url in urls:
        if dry_run:
            click.echo(f'[DRY RUN] Abriria {url}')
        else:
            click.launch(url)

if __name__ == '__main__':
    abrir()
    docs()
    help_local()
    abrir_multiplas()
    abrir_browser()
    abrir_url()
    preview()

import click

# BadParameter básico
@click.command()
@click.option('--idade', type=int)
def verificar_idade(idade):
    if idade < 0 or idade > 150:
        raise click.BadParameter('Idade deve estar entre 0 e 150')
    click.echo(f'Idade válida: {idade}')

# BadParameter com mensagem personalizada
@click.command()
@click.argument('email')
def validar_email(email):
    if '@' not in email:
        raise click.BadParameter(f'"{email}" não é um email válido')
    click.echo(f'Email válido: {email}')

# BadParameter com parâmetro
@click.command()
@click.option('--arquivo', type=click.Path(exists=True))
def processar(arquivo):
    if not arquivo.endswith('.txt'):
        raise click.BadParameter('Arquivo deve ser .txt', param_hint='--arquivo')
    click.echo(f'Processando {arquivo}')

# BadParameter em callback
def validar_senha(ctx, param, value):
    if len(value) < 8:
        raise click.BadParameter('Senha muito curta (mínimo 8 caracteres)')
    if not any(c.isdigit() for c in value):
        raise click.BadParameter('Senha deve conter pelo menos um número')
    return value

@click.command()
@click.option('--senha', callback=validar_senha)
def cadastrar(senha):
    click.echo('Cadastro realizado')

# BadParameter com context
@click.command()
@click.option('--modo', type=click.Choice(['fast', 'slow']))
def executar(modo):
    if modo == 'fast' and not click.confirm('Modo fast é perigoso. Continuar?'):
        raise click.BadParameter('Modo fast cancelado pelo usuário')
    click.echo(f'Executando no modo {modo}')

# BadParameter com múltiplos erros
def validar_porta(ctx, param, value):
    if value < 1 or value > 65535:
        raise click.BadParameter(f'Porta {value} inválida. Use 1-65535')
    return value

@click.command()
@click.option('--porta', type=int, callback=validar_porta)
def servidor(porta):
    click.echo(f'Servidor na porta {porta}')

# BadParameter com arquivo
@click.command()
@click.argument('arquivo', type=click.Path())
def ler(arquivo):
    try:
        with open(arquivo, 'r') as f:
            conteudo = f.read()
        click.echo(f'Arquivo lido: {len(conteudo)} bytes')
    except IOError as e:
        raise click.BadParameter(f'Não foi possível ler o arquivo: {e}')

# Tratamento de BadParameter
@click.command()
def testar():
    try:
        click.echo('Testando...')
        raise click.BadParameter('Erro de parâmetro')
    except click.BadParameter as e:
        click.echo(f'Capturado: {e}', err=True)

if __name__ == '__main__':
    verificar_idade()
    validar_email()
    processar()
    cadastrar()
    executar()
    servidor()
    ler()
    testar()

