import time
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

# Exemplo 1: Handler básico com todos os métodos
class MeuHandler(FileSystemEventHandler):

    def on_any_event(self, event):
        """Chamado para QUALQUER evento (catch-all)"""
        print(f'[ANY] tipo={event.event_type} path={event.src_path} is_dir={event.is_directory}')

    def on_created(self, event):
        """Chamado quando arquivo/diretório é criado"""
        if event.is_directory:
            print(f'[CREATED DIR] {event.src_path}')
        else:
            print(f'[CREATED FILE] {event.src_path}')

    def on_modified(self, event):
        """Chamado quando arquivo/diretório é modificado"""
        print(f'[MODIFIED] {event.src_path}')

    def on_deleted(self, event):
        """Chamado quando arquivo/diretório é deletado"""
        print(f'[DELETED] {event.src_path}')

    def on_moved(self, event):
        """Chamado quando arquivo/diretório é movido/renomeado"""
        print(f'[MOVED] {event.src_path} -> {event.dest_path}')

    def on_closed(self, event):
        """Chamado quando arquivo é fechado (Linux com inotify)"""
        print(f'[CLOSED] {event.src_path}')

observer = Observer()
observer.schedule(MeuHandler(), path='/tmp/monitorado', recursive=True)
observer.start()

try:
    while True:
        time.sleep(1)
except KeyboardInterrupt:
    observer.stop()
observer.join()

import time
from watchdog.observers import Observer
from watchdog.events import PatternMatchingEventHandler

# Exemplo 1: Monitorar apenas arquivos Python
class PythonHandler(PatternMatchingEventHandler):
    def __init__(self):
        super().__init__(
            patterns=['*.py'],           # padrões para incluir
            ignore_patterns=None,        # padrões para ignorar
            ignore_directories=False,    # ignorar eventos de diretórios
            case_sensitive=True           # case sensitive
        )

    def on_modified(self, event):
        print(f'[PY MODIFICADO] {event.src_path}')

    def on_created(self, event):
        print(f'[PY CRIADO] {event.src_path}')

# Exemplo 2: Monitorar múltiplos tipos, ignorando padrões
class MediaHandler(PatternMatchingEventHandler):
    def __init__(self):
        super().__init__(
            patterns=['*.jpg', '*.png', '*.gif', '*.mp4', '*.mp3'],
            ignore_patterns=['*.tmp', '*~', '*/.__*'],
            ignore_directories=True,
            case_sensitive=False  # aceita .JPG, .Png, etc.
        )

    def on_created(self, event):
        print(f'[NOVA MÍDIA] {event.src_path}')

    def on_deleted(self, event):
        print(f'[MÍDIA REMOVIDA] {event.src_path}')

# Exemplo 3: Monitorar configurações, ignorar backups
class ConfigHandler(PatternMatchingEventHandler):
    def __init__(self):
        super().__init__(
            patterns=['*.json', '*.yaml', '*.yml', '*.ini', '*.toml'],
            ignore_patterns=['*.bak', '*.backup', '*/.git/*'],
            ignore_directories=True,
            case_sensitive=True
        )

    def on_modified(self, event):
        print(f'[CONFIG ALTERADA] {event.src_path}')
        print(f'  -> Recarregando configuração...')

observer = Observer()
observer.schedule(PythonHandler(), path='/tmp/projeto', recursive=True)
observer.schedule(MediaHandler(), path='/tmp/uploads', recursive=True)
observer.schedule(ConfigHandler(), path='/tmp/config', recursive=False)
observer.start()

try:
    while True:
        time.sleep(1)
except KeyboardInterrupt:
    observer.stop()
observer.join()

import time
from watchdog.observers import Observer
from watchdog.events import RegExMatchingEventHandler

# Exemplo 1: Monitorar arquivos de log com data no nome
class LogRotateHandler(RegExMatchingEventHandler):
    def __init__(self):
        super().__init__(
            regexes=[r'.*\.log$', r'.*\.log\.\d+$'],  # .log e .log.1, .log.2
            ignore_regexes=[r'.*/\..*'],                # ignorar ocultos
            ignore_directories=True,
            case_sensitive=True
        )

    def on_created(self, event):
        print(f'[NOVO LOG] {event.src_path}')

    def on_modified(self, event):
        print(f'[LOG MODIFICADO] {event.src_path}')

# Exemplo 2: Monitorar arquivos com padrão específico no nome
class DataFileHandler(RegExMatchingEventHandler):
    def __init__(self):
        super().__init__(
            regexes=[r'.*/data_\d{4}-\d{2}-\d{2}\.csv$'],  # data_2024-01-15.csv
            ignore_regexes=None,
            ignore_directories=True,
            case_sensitive=True
        )

    def on_created(self, event):
        print(f'[NOVO DATASET] {event.src_path}')
        print(f'  -> Iniciando processamento...')

# Exemplo 3: Monitorar tudo exceto padrões complexos
class CodeHandler(RegExMatchingEventHandler):
    def __init__(self):
        super().__init__(
            regexes=[r'.*\.(py|js|ts|java|go|rs)$'],  # linguagens de programação
            ignore_regexes=[
                r'.*/__pycache__/.*',    # cache Python
                r'.*/node_modules/.*',   # node_modules
                r'.*/\.git/.*',          # git internals
                r'.*\.pyc$',            # bytecode
                r'.*\.min\.(js|css)$',  # minificados
            ],
            ignore_directories=True,
            case_sensitive=False
        )

    def on_modified(self, event):
        print(f'[CÓDIGO ALTERADO] {event.src_path}')

observer = Observer()
observer.schedule(LogRotateHandler(), path='/var/log/myapp', recursive=False)
observer.schedule(DataFileHandler(), path='/tmp/datasets', recursive=True)
observer.schedule(CodeHandler(), path='/home/dev/projeto', recursive=True)
observer.start()

try:
    while True:
        time.sleep(1)
except KeyboardInterrupt:
    observer.stop()
observer.join()

import time
from pathlib import Path
from datetime import datetime
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

# Exemplo 1: Auto-reload de configuração
class ConfigWatcher(FileSystemEventHandler):
    def __init__(self):
        super().__init__()
        self.config = {}

    def on_modified(self, event):
        if event.is_directory:
            return

        path = Path(event.src_path)
        if path.suffix in ('.json', '.yaml', '.ini'):
            timestamp = datetime.now().strftime('%H:%M:%S')
            print(f'[{timestamp}] Config modificada: {path.name}')
            print(f'  -> Recarregando configuração...')
            # Em produção: self.config = json.loads(path.read_text())
            print(f'  -> Configuração atualizada!')

# Exemplo 2: Live reload para desenvolvimento web
class LiveReloadHandler(FileSystemEventHandler):
    def __init__(self):
        super().__init__()
        self.last_reload = 0
        self.debounce_seconds = 1  # evitar reloads múltiplos

    def on_modified(self, event):
        if event.is_directory:
            return

        path = Path(event.src_path)
        if path.suffix not in ('.py', '.html', '.css', '.js'):
            return

        agora = time.time()
        if agora - self.last_reload < self.debounce_seconds:
            return  # debounce: ignorar modificações muito rápidas

        self.last_reload = agora
        print(f'[LIVE RELOAD] {path.name} modificado')
        print(f'  -> Reiniciando servidor...')

# Exemplo 3: Log de auditoria
class AuditHandler(FileSystemEventHandler):
    def on_modified(self, event):
        if event.is_directory:
            return
        path = Path(event.src_path)
        try:
            tamanho = path.stat().st_size
        except FileNotFoundError:
            tamanho = 'N/A'
        timestamp = datetime.now().isoformat()
        print(f'[AUDIT] {timestamp} | MODIFIED | {path.name} | size={tamanho}')

