def buscar(q: str):  # obrigatório porque não tem default
    return {'query': q}

# Exemplo 3: Query param opcional (None como padrão)
@app.get('/itens/busca')
def buscar_itens(q: str | None = None, categoria: str | None = None):
    resultados = {'filtros': {}}
    if q:
        resultados['filtros']['q'] = q
    if categoria:
        resultados['filtros']['categoria'] = categoria
    return resultados

# Exemplo 4: Booleano (aceita true/false/1/0/yes/no)
@app.get('/itens/listar')
def listar(ativo: bool = True, ordenar: bool = False):
    return {'ativo': ativo, 'ordenar': ordenar}

# Exemplo 5: Validação com Query()
@app.get('/produtos')
def listar_produtos(
    q: str = Query(
        default=None,
        min_length=3,            # mínimo 3 caracteres
        max_length=50,           # máximo 50 caracteres
        pattern='^[a-zA-Z]',    # regex: começar com letra
        title='Busca',
        description='Termo de busca para filtrar produtos',
        examples=['notebook']
    ),
    preco_min: float = Query(default=0, ge=0, alias='preco-min'),
    preco_max: float = Query(default=99999, le=100000, alias='preco-max'),
):
    return {'q': q, 'preco_min': preco_min, 'preco_max': preco_max}

# Exemplo 6: Lista de valores (query param repetido)
@app.get('/filtro')
def filtrar(
    tags: list[str] = Query(default=[]),
    ids: list[int] = Query(default=[])
):
    return {'tags': tags, 'ids': ids}

# Exemplo 7: Query param obrigatório com validação
@app.get('/pesquisa')
def pesquisar(
    q: str = Query(min_length=1, max_length=100),  # sem default = obrigatório
    pagina: int = Query(default=1, ge=1),
    por_pagina: int = Query(default=20, ge=1, le=100)
):
    return {'q': q, 'pagina': pagina, 'por_pagina': por_pagina}

# Exemplo 8: Depreciar um query parameter
@app.get('/v2/itens')
def listar_v2(
    q: str | None = Query(default=None),
    antigo_filtro: str | None = Query(
        default=None,
        deprecated=True,  # aparece como depreciado na docs
        description='Use "q" em vez deste parâmetro'
    )
):
    return {'q': q or antigo_filtro}

