    time.sleep(1)
    print(f'Estatísticas atualizadas para user {usuario_id}')

class UsuarioCreate(BaseModel):
    nome: str
    email: str

@app.post('/usuarios')
def criar_usuario(usuario: UsuarioCreate, background_tasks: BackgroundTasks):
    # Responde imediatamente
    resultado = {'id': 1, 'nome': usuario.nome}

    # Agenda tarefas em background
    background_tasks.add_task(enviar_email, usuario.email, 'Bem-vindo!')
    background_tasks.add_task(atualizar_estatisticas, 1)
    background_tasks.add_task(escrever_log, f'Usuário criado: {usuario.nome}')

