# === arquivo: main.py ===
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

class Item(BaseModel):
    nome: str
    preco: float

itens_db = {}

@app.get('/')
def raiz():
    return {'status': 'ok'}

@app.post('/itens', status_code=201)
def criar_item(item: Item):
    item_id = len(itens_db) + 1
    itens_db[item_id] = item.model_dump()
    return {'id': item_id, **item.model_dump()}

@app.get('/itens/{item_id}')
def get_item(item_id: int):
    if item_id not in itens_db:
        raise HTTPException(status_code=404, detail='Item não encontrado')
    return {'id': item_id, **itens_db[item_id]}

# === arquivo: test_main.py ===
from fastapi.testclient import TestClient
from main import app

client = TestClient(app)

# Teste 1: GET básico
def test_raiz():
    response = client.get('/')
    assert response.status_code == 200
    assert response.json() == {'status': 'ok'}
    print('✅ test_raiz')

# Teste 2: POST com JSON
def test_criar_item():
    response = client.post(
        '/itens',
        json={'nome': 'Mouse', 'preco': 89.90}
    )
    assert response.status_code == 201
    dados = response.json()
    assert dados['nome'] == 'Mouse'
    assert dados['preco'] == 89.90
    assert 'id' in dados
    print('✅ test_criar_item')

# Teste 3: Erro 404
def test_item_inexistente():
    response = client.get('/itens/9999')
    assert response.status_code == 404
    assert response.json()['detail'] == 'Item não encontrado'
    print('✅ test_item_inexistente')

# Teste 4: Erro de validação
def test_validacao():
    response = client.post(
        '/itens',
        json={'nome': 'Mouse'}  # faltou preco
    )
    assert response.status_code == 422
    print('✅ test_validacao')

# Teste 5: Headers e cookies
def test_com_headers():
    response = client.get(
        '/',
        headers={'X-Custom': 'valor'},
        cookies={'session': 'abc'}
    )
    assert response.status_code == 200
    print('✅ test_com_headers')

# Teste 6: Query parameters
def test_query_params():
    response = client.get('/itens', params={'skip': 0, 'limit': 10})
    print('✅ test_query_params')

# Executar testes
if __name__ == '__main__':
    test_raiz()
    test_criar_item()
    test_item_inexistente()
    test_validacao()
    test_com_headers()
    print('\n🎉 Todos os testes passaram!')

from fastapi import FastAPI, HTTPException, Query, Path, Depends
from pydantic import BaseModel, Field
from datetime import datetime
from enum import Enum

app = FastAPI(title='API de Produtos', version='1.0.0')

# === Models ===

class CategoriaEnum(str, Enum):
    eletronicos = 'eletronicos'
    roupas = 'roupas'
    alimentos = 'alimentos'
    livros = 'livros'

class ProdutoBase(BaseModel):
    nome: str = Field(min_length=2, max_length=100)
    preco: float = Field(gt=0, le=999999)
    descricao: str | None = Field(default=None, max_length=500)
    categoria: CategoriaEnum
    em_estoque: bool = True

class ProdutoCreate(ProdutoBase):
    pass

class ProdutoUpdate(BaseModel):
    nome: str | None = Field(default=None, min_length=2, max_length=100)
    preco: float | None = Field(default=None, gt=0)
    descricao: str | None = None
    categoria: CategoriaEnum | None = None
    em_estoque: bool | None = None

class ProdutoResponse(ProdutoBase):
    id: int
    criado_em: datetime
    atualizado_em: datetime

class ProdutoListResponse(BaseModel):
    total: int
    pagina: int
    por_pagina: int
    produtos: list[ProdutoResponse]

# === Banco simulado ===
db: dict[int, dict] = {}
sequencia_id = 0

def gerar_id() -> int:
    global sequencia_id
    sequencia_id += 1
    return sequencia_id

# === Dependências ===
def paginacao(
    pagina: int = Query(default=1, ge=1, description='Número da página'),
    por_pagina: int = Query(default=10, ge=1, le=100, description='Itens por página')
):
    return {'pagina': pagina, 'por_pagina': por_pagina, 'skip': (pagina - 1) * por_pagina}

# === Endpoints ===

@app.post('/produtos', response_model=ProdutoResponse, status_code=201, tags=['Produtos'])
def criar_produto(produto: ProdutoCreate):
    """Cria um novo produto"""
    agora = datetime.now()
    produto_db = {
        'id': gerar_id(),
        **produto.model_dump(),
        'criado_em': agora,
        'atualizado_em': agora
    }
    db[produto_db['id']] = produto_db
    return produto_db

@app.get('/produtos', response_model=ProdutoListResponse, tags=['Produtos'])
def listar_produtos(
    pag: dict = Depends(paginacao),
    q: str | None = Query(default=None, min_length=2, description='Buscar por nome'),
    categoria: CategoriaEnum | None = None,
    em_estoque: bool | None = None,
    ordenar: str = Query(default='nome', pattern='^(nome|preco|criado_em)$'),
):
    """Lista produtos com filtros e paginação"""
    resultados = list(db.values())

    if q:
        resultados = [p for p in resultados if q.lower() in p['nome'].lower()]
    if categoria:
        resultados = [p for p in resultados if p['categoria'] == categoria]
    if em_estoque is not None:
        resultados = [p for p in resultados if p['em_estoque'] == em_estoque]

    resultados.sort(key=lambda x: x.get(ordenar, ''))
    total = len(resultados)
    resultados = resultados[pag['skip']:pag['skip'] + pag['por_pagina']]

    return {
        'total': total,
        'pagina': pag['pagina'],
        'por_pagina': pag['por_pagina'],
        'produtos': resultados
    }

@app.get('/produtos/{produto_id}', response_model=ProdutoResponse, tags=['Produtos'])
def buscar_produto(produto_id: int = Path(ge=1)):
    """Busca produto por ID"""
    if produto_id not in db:
        raise HTTPException(status_code=404, detail=f'Produto {produto_id} não encontrado')
    return db[produto_id]

@app.patch('/produtos/{produto_id}', response_model=ProdutoResponse, tags=['Produtos'])
def atualizar_produto(produto_id: int, produto: ProdutoUpdate):
    """Atualiza parcialmente um produto"""
    if produto_id not in db:
        raise HTTPException(status_code=404, detail=f'Produto {produto_id} não encontrado')
    dados = produto.model_dump(exclude_unset=True)
    if not dados:
        raise HTTPException(status_code=400, detail='Nenhum campo para atualizar')
    db[produto_id].update(dados)
    db[produto_id]['atualizado_em'] = datetime.now()
    return db[produto_id]

@app.delete('/produtos/{produto_id}', status_code=204, tags=['Produtos'])
def deletar_produto(produto_id: int):
    """Remove um produto"""
    if produto_id not in db:
        raise HTTPException(status_code=404, detail=f'Produto {produto_id} não encontrado')
    del db[produto_id]

@app.get('/produtos/stats/resumo', tags=['Estatísticas'])
def estatisticas():
    """Estatísticas dos produtos"""
    if not db:
        return {'total': 0}
    produtos = list(db.values())
    precos = [p['preco'] for p in produtos]
    return {
        'total': len(produtos),
        'preco_medio': sum(precos) / len(precos),
        'preco_min': min(precos),
        'preco_max': max(precos),
        'em_estoque': sum(1 for p in produtos if p['em_estoque']),
        'por_categoria': {cat.value: sum(1 for p in produtos if p['categoria'] == cat) for cat in CategoriaEnum}
    }

