def track_mouse_position():
    print("Mova o mouse. Pressione Ctrl+C para sair.")
    try:
        while True:
            x, y = pyautogui.position()
            color = pyautogui.pixel(x, y)
            print(f'\rPosição: ({x:4d}, {y:4d}) | Cor RGB: {color}', end='')
            time.sleep(0.05)
    except KeyboardInterrupt:
        print('\nMonitoramento encerrado')

# Exemplo 3: Salvar coordenadas em arquivo
def save_click_coordinates():
    coordinates = []
    print("Clique nos pontos desejados. Pressione ESC para finalizar.")
    while True:
        x, y = pyautogui.position()
        print(f'Posição atual: ({x}, {y})')
        if pyautogui.prompt('Adicionar esta posição? (s/n)') == 's':
            coordinates.append((x, y))
            print(f'Posição adicionada: ({x}, {y})')
        if pyautogui.prompt('Continuar? (s/n)') != 's':
            break

    with open('coords.txt', 'w') as f:
        for x, y in coordinates:
            f.write(f'{x},{y}\n')
    print(f'{len(coordinates)} coordenadas salvas em coords.txt')

