# Exemplo 1: Cache baseado em argumentos
from prefect import task, flow

@task(cache_key_fn=lambda self, x: x, cache_expiration=3600)
def calcular_valor(x):
    import time
    time.sleep(2)
    return x * 100

@flow
def fluxo_cache():
    # Primeira execução: processa
    result1 = calcular_valor(10)
    # Segunda execução: usa cache
    result2 = calcular_valor(10)
    # Argumento diferente: processa novamente
    result3 = calcular_valor(20)
    return result1, result2, result3

