# Exemplo 4: Aguardar primeiro resultado
from prefect.futures import wait, FIRST_COMPLETED

@flow
def fluxo_primeiro():
    futures = [
        api_call.submit('endpoint1'),
        api_call.submit('endpoint2'),
        api_call.submit('endpoint3')
    ]

    done, pending = wait(futures, timeout=5, return_when=FIRST_COMPLETED)
    primeiro = list(done)[0].result()
    return primeiro

