# Exemplo 1: Emitir métrica simples
from prefect import flow, task
from prefect.metrics import increment_counter, record_histogram

@flow
def fluxo_metricas():
    increment_counter('fluxos.executados', tags={'ambiente': 'prod'})

    for i in range(100):
        processar_item(i)

@task
def processar_item(item):
    import time
    start = time.time()

    # Processamento
    time.sleep(0.01)

    duration = time.time() - start
    record_histogram('processamento.duracao', duration, buckets=[0.005, 0.01, 0.05, 0.1])
    increment_counter('itens.processados')

