@task
def tarefa_metricada(url):
    import requests

    response = requests.get(url)
    increment_counter('api.chamadas', tags={'endpoint': url, 'status': response.status_code})
    record_histogram('api.tempo_resposta', response.elapsed.total_seconds())

    return response.json()

# Código que gera o erro
from prefect import flow, task

@task(timeout_seconds=5)
def tarefa_lenta():
    import time
    time.sleep(10)
    return 'Concluída'

@flow
def fluxo_timeout():
    resultado = tarefa_lenta()
    return resultado

# Solução: aumentar timeout ou otimizar tarefa
@task(timeout_seconds=15)
def tarefa_otimizada():
    import time
    time.sleep(10)
    return 'Concluída'

# Alternativa: capturar exceção e tratar
@flow
def fluxo_com_retry():
    try:
        resultado = tarefa_lenta()
    except TimeoutError:
        print('Tarefa expirou, usando fallback')
        return 'Fallback'
    return resultado

# Melhor prática: usar retry
@task(timeout_seconds=5, retries=2, retry_delay_seconds=1)
def tarefa_com_retry():
    import time
    time.sleep(10)
    return 'Sucesso'

