from django.db import connection

def tabela_existe(nome_tabela):
    with connection.cursor() as cursor:
        cursor.execute("""
            SELECT EXISTS (
                SELECT FROM information_schema.tables 
                WHERE table_name = %s
            )
        """, [nome_tabela])
        return cursor.fetchone()[0]

