# Exemplo 2: WebSocket com broadcast
class ChatHandler(tornado.websocket.WebSocketHandler):
    clients = set()

    def open(self):
        self.clients.add(self)
        self.broadcast(f'Usuário {self.request.remote_ip} entrou')

    def on_message(self, message):
        self.broadcast(f'[{self.request.remote_ip}]: {message}')

    def on_close(self):
        self.clients.remove(self)
        self.broadcast(f'Usuário {self.request.remote_ip} saiu')

    def broadcast(self, message):
        for client in self.clients:
            client.write_message(message)

# Exemplo 3: WebSocket com autenticação
class AuthWebSocketHandler(tornado.websocket.WebSocketHandler):
    def check_origin(self, origin):
        # Verificar origem permitida
        return True

    def open(self, *args, **kwargs):
        token = self.get_argument('token', None)
        if not token or not self.validate_token(token):
            self.close(reason='Autenticação falhou')
            return
        self.user = self.get_user_from_token(token)

    def validate_token(self, token):
        return token == 'secret'

# Exemplo 4: WebSocket com ping/pong
class PingHandler(tornado.websocket.WebSocketHandler):
    def open(self):
        self.ping_interval = tornado.ioloop.PeriodicCallback(self.send_ping, 30000)
        self.ping_interval.start()

    def send_ping(self):
        self.ping(b'ping')

    def on_pong(self, data):
        print(f'Pong recebido: {data}')

    def on_close(self):
        if self.ping_interval:
            self.ping_interval.stop()

