# Exemplo 1: Queue básica
import tornado.queues
import tornado.gen

@tornado.gen.coroutine
def producer(queue):
    for i in range(10):
        yield queue.put(i)
        print(f'Produzido: {i}')
    yield queue.put(None)  # Sinal de fim

@tornado.gen.coroutine
def consumer(queue):
    while True:
        item = yield queue.get()
        if item is None:
            break
        print(f'Consumido: {item}')
        yield tornado.gen.sleep(0.5)

@tornado.gen.coroutine
def main():
    queue = tornado.queues.Queue(maxsize=5)
    yield [producer(queue), consumer(queue)]

# Exemplo 2: Queue com timeout
@tornado.gen.coroutine
def get_with_timeout(queue):
    try:
        item = yield queue.get(timeout=2.0)
        print(f'Obtido: {item}')
    except tornado.gen.TimeoutError:
        print('Timeout aguardando item')

# Exemplo 3: Queue com prioridade
class PriorityQueue(tornado.queues.Queue):
    def __init__(self, maxsize=0):
        super().__init__(maxsize)

    def _put(self, item):
        self.queue.append(item)
        self.queue.sort()  # Ordenar por prioridade

@tornado.gen.coroutine
def priority_example():
    queue = PriorityQueue()
    yield queue.put((2, 'task_medium'))
    yield queue.put((1, 'task_high'))
    yield queue.put((3, 'task_low'))

    while not queue.empty():
        priority, task = yield queue.get()
        print(f'Executando: {task} (prio {priority})')

# Exemplo 4: Queue com join
@tornado.gen.coroutine
def producer_consumer_with_join():
    queue = tornado.queues.Queue()

    @tornado.gen.coroutine
    def producer():
        for i in range(5):
            yield queue.put(i)
            print(f'Prod: {i}')

    @tornado.gen.coroutine
    def consumer():
        while True:
            item = yield queue.get()
            print(f'Cons: {item}')
            queue.task_done()

    tornado.ioloop.IOLoop.current().spawn_callback(consumer)
    yield producer()
    yield queue.join()
    print('Todos processados')

# Exemplo 5: Queue com múltiplos consumidores
@tornado.gen.coroutine
def worker(queue, worker_id):
    while True:
        item = yield queue.get()
        if item is None:
            break
        print(f'Worker {worker_id} processando {item}')
        yield tornado.gen.sleep(1)
        queue.task_done()

@tornado.gen.coroutine
def multi_consumer():
    queue = tornado.queues.Queue()

    for i in range(3):
        tornado.ioloop.IOLoop.current().spawn_callback(worker, queue, i)

    for i in range(20):
        yield queue.put(i)

    # Aguardar processamento
    yield queue.join()

    # Sinalizar fim
    for i in range(3):
        yield queue.put(None)

