# Exemplo 5: Protocolo customizado
class CustomProtocol(tornado.tcpserver.TCPServer):
    def __init__(self):
        super().__init__()
        self.clients = set()

    @tornado.gen.coroutine
    def handle_stream(self, stream, address):
        self.clients.add(stream)
        try:
            while True:
                data = yield stream.read_until(b'\n')
                yield self.broadcast(data, exclude=stream)
        finally:
            self.clients.remove(stream)

    def broadcast(self, data, exclude=None):
        for client in self.clients:
            if client != exclude:
                client.write(data)

