@tornado.gen.coroutine
def fetch_with_retry():
    http_client = tornado.httpclient.AsyncHTTPClient()
    for attempt in range(3):
        try:
            response = yield http_client.fetch('http://slow-server.com', request_timeout=5)
            return response
        except tornado.httpclient.HTTPError as e:
            if e.code == 599 and attempt < 2:
                yield tornado.gen.sleep(2 ** attempt)
                continue
            raise

