# Ping periódico para detectar fechamento
class HeartbeatHandler(tornado.websocket.WebSocketHandler):
    def open(self):
        self.heartbeat = tornado.ioloop.PeriodicCallback(self.ping, 30000)
        self.heartbeat.start()

    def ping(self):
        try:
            self.ping(b'ping')
        except tornado.websocket.WebSocketClosedError:
            self.heartbeat.stop()

    def on_close(self):
        if self.heartbeat:
            self.heartbeat.stop()

