# Código que gera ResponseError
import redis
r = redis.Redis(decode_responses=True)

# Exemplo 1: Operação em tipo errado
r.set('string_key', 'valor')
try:
 # Tentar usar operação de lista em string
 r.lpush('string_key', 'item')
except redis.ResponseError as e:
 print(f'Erro: {e}')

# Exemplo 2: Comando com sintaxe inválida
try:
 r.execute_command('INVALID_COMMAND')
except redis.ResponseError as e:
 print(f'Erro: {e}')

# Exemplo 3: Operação em chave inexistente com tipo específico
try:
 r.lpop('nao_existe')
except redis.ResponseError:
 print('Chave não é lista')

# Exemplo 4: Tratamento de erro com verificação de tipo
key = 'my_key'
key_type = r.type(key)
if key_type == 'string':
 print(r.get(key))
elif key_type == 'list':
 print(r.lrange(key, 0, -1))
else:
 print(f'Tipo não suportado: {key_type}')

# Exemplo 5: Erro em pipeline com transação
r.set('counter', 'not_a_number')
pipe = r.pipeline(transaction=True)
pipe.watch('counter')
try:
 pipe.multi()
 pipe.incr('counter') # Erro: não é inteiro
 pipe.execute()
except redis.ResponseError as e:
 print(f'Erro na transação: {e}')
 pipe.reset() # Reseta o pipeline

# Exemplo 6: Erro de limite de memória
# Se o Redis estiver com maxmemory configurado
try:
 r.set('large_key', 'x' * (1024 * 1024 * 100)) # 100MB
except redis.ResponseError as e:
 if 'OOM' in str(e):
 print('Erro de memória: Redis está em OOM')

# Exemplo 7: Erro em comando Lua script
script = 'return redis.call('GET', KEYS[1]) + 1'
try:
 result = r.execute_command('EVAL', script, 1, 'string_key')
except redis.ResponseError as e:
 print(f'Erro no script: {e}')

# Exemplo 8: Tratamento específico por código de erro
try:
 r.set('key', 'value', nx=True, xx=True) # NX e XX não podem ser usados juntos
except redis.ResponseError as e:
 if 'syntax error' in str(e).lower():
 print('Erro de sintaxe no comando')
 else:
 print(f'Outro erro: {e}')

