import motor.motor_asyncio
import asyncio

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']

    # Exemplo 1: Criar coleção simples
    collection = await db.create_collection('nova_colecao')
    print(f'Criada: {collection.name}')

    # Exemplo 2: Capped collection (tamanho fixo)
    collection = await db.create_collection(
        'logs_circular',
        capped=True,
        size=1048576,  # 1MB
        max=1000  # Máximo 1000 documentos
    )
    print(f'Capped: {collection.name}')

    # Exemplo 3: Com validação de schema
    validator = {
        '$jsonSchema': {
            'bsonType': 'object',
            'required': ['nome', 'email'],
            'properties': {
                'nome': {
                    'bsonType': 'string',
                    'description': 'deve ser string e é obrigatório'
                },
                'email': {
                    'bsonType': 'string',
                    'pattern': '^.+@.+\\..+$',
                    'description': 'deve ser email válido'
                },
                'idade': {
                    'bsonType': 'int',
                    'minimum': 0,
                    'maximum': 150
                }
            }
        }
    }
    collection = await db.create_collection(
        'usuarios_validados',
        validator=validator,
        validationLevel='strict',
        validationAction='error'
    )
    print(f'Com validação: {collection.name}')

    # Exemplo 4: Com collation (ordenação por idioma)
    collection = await db.create_collection(
        'textos_pt',
        collation={'locale': 'pt', 'strength': 2}
    )
    print(f'Com collation: {collection.name}')

asyncio.run(main())

