    }).to_list(None)
    print(f'Entre 50 e 500: {len(docs)}')

    # Exemplo 4: $in - Dentro da lista
    docs = await col.find({
        'categoria': {'$in': ['eletronicos', 'informatica']}
    }).to_list(None)
    print(f'Categorias específicas: {len(docs)}')

    # Exemplo 5: $nin - Não está na lista
    docs = await col.find({
        'status': {'$nin': ['removido', 'expirado']}
    }).to_list(None)
    print(f'Não removidos/expirados: {len(docs)}')

    # Exemplo 6: $and - E lógico
    docs = await col.find({
        '$and': [
            {'preco': {'$gt': 100}},
            {'estoque': {'$gt': 0}}
        ]
    }).to_list(None)
    print(f'Caros com estoque: {len(docs)}')

    # Exemplo 7: $or - Ou lógico
    docs = await col.find({
        '$or': [
            {'preco': {'$lt': 50}},
            {'promocao': True}
        ]
    }).to_list(None)
    print(f'Baratos ou em promoção: {len(docs)}')

    # Exemplo 8: $not - Negação
    docs = await col.find({
        'preco': {'$not': {'$gt': 1000}}
    }).to_list(None)
    print(f'Não mais que 1000: {len(docs)}')

    # Exemplo 9: $exists - Campo existe
    docs = await col.find({'desconto': {'$exists': True}}).to_list(None)
    print(f'Com desconto: {len(docs)}')

    # Exemplo 10: $type - Tipo do campo
    docs = await col.find({'preco': {'$type': 'double'}}).to_list(None)
    print(f'Preço é double: {len(docs)}')

    # Exemplo 11: $regex - Expressão regular
    docs = await col.find({
        'nome': {'$regex': '^Note', '$options': 'i'}
    }).to_list(None)
    print(f'Começa com Note: {len(docs)}')

    # Exemplo 12: $size - Tamanho de array
    docs = await col.find({'tags': {'$size': 3}}).to_list(None)
    print(f'Exatamente 3 tags: {len(docs)}')

    # Exemplo 13: $all - Array contém todos
    docs = await col.find({
        'tags': {'$all': ['novo', 'destaque']}
    }).to_list(None)
    print(f'Novos e destaques: {len(docs)}')

    # Exemplo 14: $elemMatch - Elemento do array
    docs = await col.find({
        'avaliacoes': {
            '$elemMatch': {'nota': {'$gte': 4}, 'verificado': True}
        }
    }).to_list(None)
    print(f'Avaliações verificadas >= 4: {len(docs)}')

asyncio.run(main())

