import motor.motor_asyncio
import asyncio
from pymongo import GEO2DSPHERE

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']
    col = db['lugares']

    # Criar índice geoespacial
    await col.create_index([('localizacao', GEO2DSPHERE)])

    # Inserir dados
    await col.insert_many([
        {
            'nome': 'Restaurante A',
            'localizacao': {'type': 'Point', 'coordinates': [-46.6334, -23.5505]}
        },
        {
            'nome': 'Restaurante B',
            'localizacao': {'type': 'Point', 'coordinates': [-46.6544, -23.5635]}
        },
        {
            'nome': 'Restaurante C',
            'localizacao': {'type': 'Point', 'coordinates': [-46.6258, -23.5338]}
        }
    ])

    # Exemplo 1: Buscar próximos a um ponto
    cursor = col.find({
        'localizacao': {
            '$near': {
                '$geometry': {
                    'type': 'Point',
                    'coordinates': [-46.6340, -23.5489]
                },
                '$maxDistance': 5000  # 5km em metros
            }
        }
    })
    print('Próximos (até 5km):')
    async for doc in cursor:
        print(f'  {doc["nome"]}')

    # Exemplo 2: Buscar dentro de um polígono
    cursor = col.find({
        'localizacao': {
            '$geoWithin': {
                '$geometry': {
                    'type': 'Polygon',
                    'coordinates': [[
                        [-46.66, -23.56],
                        [-46.62, -23.56],
                        [-46.62, -23.53],
                        [-46.66, -23.53],
                        [-46.66, -23.56]
                    ]]
                }
            }
        }
    })
    print('\nDentro da área:')
    async for doc in cursor:
        print(f'  {doc["nome"]}')

    # Exemplo 3: Agregação com $geoNear
    pipeline = [
        {
            '$geoNear': {
                'near': {'type': 'Point', 'coordinates': [-46.6340, -23.5489]},
                'distanceField': 'distancia',
                'maxDistance': 10000,
                'spherical': True
            }
        }
    ]
    print('\nCom distância:')
    async for doc in col.aggregate(pipeline):
        print(f'  {doc["nome"]}: {doc["distancia"]:.0f} metros')

asyncio.run(main())

