import motor.motor_asyncio
import asyncio
from pymongo.errors import OperationFailure

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']

    # Código que gera o erro - validação de schema
    try:
        # Criar coleção com validação
        await db.create_collection('validada', validator={
            '$jsonSchema': {
                'bsonType': 'object',
                'required': ['nome', 'email'],
                'properties': {
                    'nome': {'bsonType': 'string'},
                    'email': {'bsonType': 'string'}
                }
            }
        })
    except OperationFailure:
        pass  # Coleção já existe

    try:
        await db['validada'].insert_one({'nome': 123})  # nome deve ser string
    except OperationFailure as e:
        print(f'Tipo: {type(e).__name__}')
        print(f'Código: {e.code}')
        print(f'Erro: Validação de schema falhou')

    # Código que gera o erro - comando inválido
    try:
        await db.command('comandoInexistente')
    except OperationFailure as e:
        print(f'\nComando inválido: {e}')

    # Solução: tratar erros com try/except
    try:
        await db['validada'].insert_one({'nome': 'João', 'email': 'joao@email.com'})
        print('\nInserido com validação OK')
    except OperationFailure as e:
        print(f'Falha na operação: {e}')

asyncio.run(main())
